Output getEmptyOutput() {
    return root.output;
  }

void visit(BiConsumer<BytesRef, Output> consumer) {
    assert status == Status.BUILDING;
    if (root.output != null) {
      consumer.accept(new BytesRef(), root.output);
    }
    visit(root.firstChild, new BytesRefBuilder(), consumer);
