      index.writeByte((byte) node.childLabels[0]);
      writeLongNBytes(childDeltaFp, childFpBytes, index);
      if (node.output != null) {
        Output output = node.output;
        long encodedFp = encodeFP(output);
        writeLongNBytes(encodedFp, encodedOutputFpBytes, index);
