      super(termsEnum);
      iterator = termData.iterator();
      seekTerm = iterator.next();
    }
    @Override
    protected AcceptStatus accept(BytesRef term) throws IOException {
      int cmp = 0;
      while (seekTerm != null && (cmp = seekTerm.compareTo(term)) < 0) {
        seekTerm = iterator.next();
