    if (useCollection == true) {
      DocumentClusteringEngine engine = documentClusteringEngines.get(name);
      if (engine != null) {
        checkAvailable(name, engine);
        boolean useDocSet = params.getBool(ClusteringParams.USE_DOC_SET, false);
