@Override
  public BytesRef next() throws IOException {
    clearTermState();
    if (blockHeader == null) {
      long blockStartFP = getOrCreateDictionaryBrowser().seekBlock(seekTerm);
      if (isBeyondLastTerm(seekTerm, blockStartFP)) {
        return null;
      }
      if (nextBlockMatchingPrefix() == false) {
        return null;
      }
