      blockPrefixLen = browser.getBlockPrefixLen();
      blockPrefixRunAutomatonState = runAutomatonForState(blockKey.bytes, blockKey.offset, blockPrefixLen, 0);
      if (isBeyondCommonPrefix(blockKey)) {
        return false;
