    protected boolean nextString() {
      int state;
      int pos = 0;
      savedStates.grow(seekBytesRef.length()+1);
      savedStates.setIntAt(0, 0);
      while (true) {
        curGen++;
        linear = false;
        for (state = savedStates.intAt(pos); pos < seekBytesRef.length(); pos++) {
