              setLinear(seekBytesRef.length()-1);
            }
          }
          return true;
        }
      }
      return false;
    }
    protected int backtrack(int position) {
      while (position-- > 0) {
        int nextChar = seekBytesRef.byteAt(position) & 0xff;
        if (nextChar++ != 0xff) {
          seekBytesRef.setByteAt(position, (byte) nextChar);
          seekBytesRef.setLength(position+1);
          return position;
        }
      }
      return -1;
    }
  }
