      PackedInts.Mutable ranks = PackedInts.getMutable(rankIndex, 16, PackedInts.DEFAULT); // Char = 16 bit
      for (int i = 0 ; i < rankIndex ; i++) {
        ranks.set(i, buildRank[i]);
      }
      rank = LongCompressor.compress(ranks);
    }

