        oldDoc = RealTimeGetComponent.getInputDocument(core, indexedDocId);
        if (null == oldDoc) {
          return true;
        }
      }
      if (oldDoc != null) {
        oldUserVersion = oldDoc.getFieldValue(versionFieldName);
