   */
  public BasicModel getBasicModel() {
    return basicModel;
  }

  /**
   * Returns the first normalization
   */
  public AfterEffect getAfterEffect() {
    return afterEffect;
  }

  /**
   * Returns the second normalization
   */
  public Normalization getNormalization() {
    return normalization;
  }
}

