      return new ConstantDateValue(Instant.parse(param).toEpochMilli());
    } catch (DateTimeParseException e) {
      throw new SolrException(ErrorCode.BAD_REQUEST,"The parameter "+param+" could not be cast to any constant.");
    }

  });

