        lastDocID = doc;

        double minXValue = getDocValue(minX, doc);
        if (minX.docID() != doc) {
          return null;
        } else {
          double minYValue = getDocValue(minY, doc);
          double maxXValue = getDocValue(maxX, doc);
          double maxYValue = getDocValue(maxY, doc);
