private static class LongCounts {
    static final float LOAD_FACTOR = 0.7f;
    long numAdds;
    long[] vals;
    int[] counts;
    int[] oldToNewMapping;
    int cardinality;
    int threshold;
    LongCounts(int sz) {
      vals = new long[sz];
      counts = new int[sz];
      threshold = (int) (sz * LOAD_FACTOR);
    }
    int numSlots() {
      return vals.length;
    }
    private int hash(long val) {
      int h = (int) (val + (val >>> 44) + (val >>> 15));
      return h;
    }
    int add(long val) {
      if (cardinality >= threshold) {
        rehash();
      }
      numAdds++;
      int h = hash(val);
      for (int slot = h & (vals.length-1);  ;slot = (slot + ((h>>7)|1)) & (vals.length-1)) {
        int count = counts[slot];
        if (count == 0) {
          counts[slot] = 1;
          vals[slot] = val;
          cardinality++;
          return slot;
        } else if (vals[slot] == val) {
          counts[slot] = count + 1;
          return slot;
        }
      }
    }
    protected void rehash() {
      long[] oldVals = vals;
      int[] oldCounts = counts;
      int newCapacity = vals.length << 1;
      vals = new long[newCapacity];
      counts = new int[newCapacity];
      threshold = (int) (newCapacity * LOAD_FACTOR);
      for (int i=0; i<oldVals.length; i++) {
        int count = oldCounts[i];
        if (count == 0) {
          oldCounts[i] = -1;
          continue;
        }
