  private boolean discountOverlaps;
  private Independence independenceMeasure;

  @Override
  public void init(SolrParams params) {
    super.init(params);
    discountOverlaps = params.getBool(ClassicSimilarityFactory.DISCOUNT_OVERLAPS, true);
