        path.intersects(maxZPlane, notableMaxZPoints, minZPlane, minXPlane, maxXPlane, minYPlane, maxYPlane)) {
      return OVERLAPS;
    }
    if (insideRectangle == ALL_INSIDE) {
      return WITHIN;
    }
    if (insideShape == ALL_INSIDE) {
      return CONTAINS;
    }
    return DISJOINT;
  }

