  }

  @Override
  boolean twoPhaseCurrentDocMatches() throws IOException {
    subSpansToFirstStartPosition();
    while (true) {
      if (! stretchToOrder()) {
        return false;
      }
      if (shrinkToAfterShortestMatch()) {
        atFirstInCurrentDoc = true;
        return true;
      }
